 1	import {
 2	  ListPageBody,
 3	  VirtualizedTable,
 4	  getGroupVersionKindForModel,
 5	  useK8sWatchResource,
 6	  useListPageFilter,
 7	} from '@openshift-console/dynamic-plugin-sdk';
 8	import * as React from 'react';
 9	import { PipelineRunModel, RepositoryModel } from '../../models';
10	import { PipelineRunKind, RepositoryKind } from '../../types';
11	import useRepositoriesColumns from './useRepositoriesColumns';
12	import RepositoriesRow from './RepositoriesRow';
13	import { useGetTaskRuns } from '../hooks/useTektonResult';
14	import { useParams } from 'react-router-dom-v5-compat';
15	import { useTranslation } from 'react-i18next';
16	import { ListPageFilter } from '../list-pages/ListPageFilter';
17	
18	type RepositoriesListProps = {
19	  namespace?: string;
20	  hideTextFilter?: boolean;
21	};
22	
23	const RepositoriesList: React.FC<RepositoriesListProps> = ({
24	  namespace,
25	  hideTextFilter,
26	}) => {
27	  const { t } = useTranslation('plugin__pipelines-console-plugin');
28	  const { ns } = useParams();
29	  namespace = namespace || ns;
30	  const columns = useRepositoriesColumns(namespace);
31	  const [repositories, repositoriesLoaded, repositoriesLoadError] =
32	    useK8sWatchResource<RepositoryKind[]>({
33	      groupVersionKind: getGroupVersionKindForModel(RepositoryModel),
34	      isList: true,
35	      namespace,
36	      optional: true,
37	    });
38	  const [pipelineRuns, pipelineRunsLoaded] = useK8sWatchResource<
39	    PipelineRunKind[]
40	  >({
41	    isList: true,
42	    groupVersionKind: getGroupVersionKindForModel(PipelineRunModel),
43	    namespace,
44	    optional: true,
45	  });
46	  const [taskRuns, taskRunsLoaded] = useGetTaskRuns(namespace);
47	  const [staticData, filteredData, onFilterChange] =
48	    useListPageFilter(repositories);
49	
50	  return (
51	    <ListPageBody>
52	      <ListPageFilter
53	        data={staticData}
54	        onFilterChange={onFilterChange}
55	        loaded={repositoriesLoaded}
56	        hideNameLabelFilters={hideTextFilter}
57	      />
58	      <VirtualizedTable
59	        EmptyMsg={() => (
60	          <div className="cp-text-align-center" id="no-resource-msg">
61	            {t('No Repositories found')}
62	          </div>
63	        )}
64	        columns={columns}
65	        data={filteredData}
66	        loaded={repositoriesLoaded && pipelineRunsLoaded}
67	        loadError={repositoriesLoadError}
68	        Row={RepositoriesRow}
69	        rowData={{
70	          taskRuns,
71	          pipelineRuns,
72	          taskRunsLoaded,
73	        }}
74	        unfilteredData={staticData}
75	      />
76	    </ListPageBody>
77	  );
78	};
79	
80	export default RepositoriesList;

