  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import * as React from 'react';
 10	import { PipelineRunKind, RepositoryKind, TaskRunKind } from '../../types';
 11	import { Link } from 'react-router-dom-v5-compat';
 12	import { PipelineRunModel, RepositoryModel } from '../../models';
 13	import { getLatestRun } from '../utils/pipeline-augment';
 14	import { getTaskRunsOfPipelineRun } from '../hooks/useTaskRuns';
 15	import { pipelineRunDuration } from '../utils/pipeline-utils';
 16	import PipelineRunStatus from '../pipelines-list/status/PipelineRunStatus';
 17	import {
 18	  pipelineRunFilterReducer,
 19	  pipelineRunTitleFilterReducer,
 20	} from '../utils/pipeline-filter-reducer';
 21	import { getReferenceForModel } from '../pipelines-overview/utils';
 22	import LinkedPipelineRunTaskStatus from '../pipelines-list/status/LinkedPipelineRunTaskStatus';
 23	import RepositoriesKebab from './RepositoriesKebab';
 24	import { RepositoryFields, RepositoryLabels } from '../../consts';
 25	
 26	export const repositoriesTableColumnClasses = [
 27	  'pf-v5-u-w-16-on-xl pf-v6-u-w-25-on-lg pf-v6-u-w-33-on-xs', // name
 28	  'pf-v5-u-w-12-on-xl pf-v5-u-w-20-on-lg pf-v5-u-w-30-on-xs', // namespace
 29	  'pf-v5-u-w-12-on-xl pf-v5-u-w-20-on-lg pf-v5-u-w-30-on-xs', // Event type
 30	  'pf-v5-u-w-12-on-xl pf-v5-u-w-20-on-lg pf-v5-u-w-30-on-xs', // Last run
 31	  'pf-v5-u-w-16-on-xl pf-v6-u-w-25-on-lg pf-v6-u-w-33-on-xs', // Task status
 32	  'pf-m-hidden pf-m-visible-on-xl', // last run status
 33	  'pf-m-hidden pf-v5-u-w-12-on-xl pf-v5-u-w-20-on-lg pf-v6-u-w-33-on-xs pf-m-visible-on-xl', // Last run time
 34	  'pf-m-hidden pf-m-visible-on-xl', // Last run duration
 35	  'dropdown-kebab-pf pf-v6-c-table__action',
 36	];
 37	
 38	const RepositoriesRow: React.FC<
 39	  RowProps<
 40	    RepositoryKind,
 41	    {
 42	      taskRuns: TaskRunKind[];
 43	      pipelineRuns: PipelineRunKind[];
 44	      taskRunsLoaded: boolean;
 45	    }
 46	  >
 47	> = ({
 48	  obj,
 49	  activeColumnIDs,
 50	  rowData: { taskRuns, pipelineRuns, taskRunsLoaded },
 51	}) => {
 52	  const {
 53	    metadata: { name, namespace },
 54	  } = obj;
 55	  const plrs = pipelineRuns.filter((plr) => {
 56	    return (
 57	      plr.metadata?.labels?.[RepositoryLabels[RepositoryFields.REPOSITORY]] ===
 58	      obj.metadata.name
 59	    );
 60	  });
 61	  const latestRun = getLatestRun(plrs, 'creationTimestamp');
 62	
 63	  const latestPLREventType =
 64	    latestRun &&
 65	    latestRun?.metadata?.labels?.[
 66	      RepositoryLabels[RepositoryFields.EVENT_TYPE]
 67	    ];
 68	
 69	  const PLRTaskRuns = getTaskRunsOfPipelineRun(
 70	    taskRuns,
 71	    latestRun?.metadata?.name,
 72	  );
 73	  return (
 74	    <>
 75	      <TableData
 76	        className={repositoriesTableColumnClasses[0]}
 77	        id="name"
 78	        activeColumnIDs={activeColumnIDs}
 79	      >
 80	        <ResourceIcon
 81	          groupVersionKind={getGroupVersionKindForModel(RepositoryModel)}
 82	        />
 83	        <Link
 84	          to={`/k8s/ns/${namespace}/${getReferenceForModel(
 85	            RepositoryModel,
 86	          )}/${name}/Runs`}
 87	          className="co-resource-item__resource-name"
 88	          data-test-id={name}
 89	        >
 90	          {name}
 91	        </Link>
 92	      </TableData>
 93	      <TableData
 94	        className={repositoriesTableColumnClasses[1]}
 95	        id="namespace"
 96	        activeColumnIDs={activeColumnIDs}
 97	      >
 98	        <ResourceLink kind="Namespace" name={obj.metadata.namespace} />
 99	      </TableData>
100	      <TableData
101	        className={repositoriesTableColumnClasses[2]}
102	        id="event-type"
103	        activeColumnIDs={activeColumnIDs}
104	      >
105	        {latestPLREventType || '-'}
106	      </TableData>
107	      <TableData
108	        className={repositoriesTableColumnClasses[3]}
109	        id="last-run"
110	        activeColumnIDs={activeColumnIDs}
111	      >
112	        {latestRun ? (
113	          <ResourceLink
114	            groupVersionKind={getGroupVersionKindForModel(PipelineRunModel)}
115	            name={latestRun?.metadata.name}
116	            namespace={namespace}
117	          />
118	        ) : (
119	          '-'
120	        )}
121	      </TableData>
122	      <TableData
123	        className={repositoriesTableColumnClasses[4]}
124	        id="task-status"
125	        activeColumnIDs={activeColumnIDs}
126	      >
127	        {}
128	        {latestRun ? (
129	          <LinkedPipelineRunTaskStatus
130	            pipelineRun={latestRun}
131	            taskRuns={PLRTaskRuns}
132	            taskRunsLoaded={taskRunsLoaded}
133	          />
134	        ) : (
135	          '-'
136	        )}
137	      </TableData>
138	      <TableData
139	        className={repositoriesTableColumnClasses[5]}
140	        id="last-run-status"
141	        activeColumnIDs={activeColumnIDs}
142	      >
143	        {
144	          <PipelineRunStatus
145	            status={pipelineRunFilterReducer(latestRun)}
146	            title={pipelineRunTitleFilterReducer(latestRun)}
147	            pipelineRun={latestRun}
148	            taskRuns={PLRTaskRuns}
149	            taskRunsLoaded={taskRunsLoaded}
150	          />
151	        }
152	      </TableData>
153	      <TableData
154	        className={repositoriesTableColumnClasses[6]}
155	        id="last-runtime"
156	        activeColumnIDs={activeColumnIDs}
157	      >
158	        {<Timestamp timestamp={latestRun?.status.startTime} />}
159	      </TableData>
160	      <TableData
161	        className={repositoriesTableColumnClasses[7]}
162	        id="last-run-duration"
163	        activeColumnIDs={activeColumnIDs}
164	      >
165	        {pipelineRunDuration(latestRun)}
166	      </TableData>
167	      <TableData
168	        className={repositoriesTableColumnClasses[8]}
169	        id="kebab-menu"
170	        activeColumnIDs={activeColumnIDs}
171	      >
172	        <RepositoriesKebab obj={obj} />
173	      </TableData>
174	    </>
175	  );
176	};
177	
178	export default RepositoriesRow;

